_alias_to_required = {
    "STEEL": "STEEL", "钢铁": "STEEL",
    "POWER": "POWER", "电力": "POWER", "火电": "POWER",
    "CEMENT": "CEMENT", "水泥": "CEMENT",
    "CERAMICS": "CERAMICS", "陶瓷": "CERAMICS",
    "GLASS": "GLASS", "玻璃": "GLASS",
    "COKING": "COKING", "焦化": "COKING", "炼焦": "COKING"
}
_required_order = ["STEEL", "POWER", "CEMENT", "CERAMICS", "GLASS", "COKING"]

def _norm_industry_key(x):
    s = str(x).strip()
    return _alias_to_required.get(s, _alias_to_required.get(s.upper(), s.upper()))

def _extract_totals_from_dict(d):
    out = {}
    for k, v in d.items():
        nk = _norm_industry_key(k)
        if nk in _required_order and v is not None:
            out[nk] = float(v)
    return out

def _extract_totals_from_df(df):
    out = {}
    if df is None or len(df) == 0:
        return out
    cols = list(df.columns)
    ind_col = industry_col if 'industry_col' in vars() and industry_col in cols else None
    if ind_col is None:
        for c in cols:
            vals = set(str(x).strip().upper() for x in df[c].dropna().unique()[:20])
            if vals & set(_required_order):
                ind_col = c
                break
    val_candidates = [
        "exhaust_gas", "total_exhaust_gas", "total_exhaust", "exhaust_total",
        "sum_exhaust_gas", "exhaust_gas_sum", "total_flue_gas"
    ]
    val_col = next((c for c in val_candidates if c in cols), None)
    if val_col is None:
        numeric_cols = [c for c in cols if c != ind_col and pd.api.types.is_numeric_dtype(df[c])]
        exhaust_like = [c for c in numeric_cols if "exhaust" in str(c).lower()]
        val_col = exhaust_like[0] if exhaust_like else (numeric_cols[0] if numeric_cols else None)
    if ind_col is None or val_col is None:
        return out
    tmp = df[[ind_col, val_col]].dropna()
    for _, r in tmp.iterrows():
        nk = _norm_industry_key(r[ind_col])
        if nk in _required_order and r[val_col] is not None:
            out[nk] = float(r[val_col])
